  it('EXPOSEs port 3000', () => {
    const content = readFileSync(dockerfilePath, 'utf-8');
    assert.match(content, /EXPOSE\s+3000/);
  });

  it('sets NODE_ENV=production', () => {
    const content = readFileSync(dockerfilePath, 'utf-8');
    assert.ok(content.includes('NODE_ENV=production'));
